public class Main {
    public static void main(String[] args) {
        int age = Integer.parseInt(args[0]);
        if(age < 0) {
            System.out.println("Tuổi không hợp lệ");
            return;
        }

        String result = age >= 18 ? "Bạn đã trưởng thành" : "Bạn chưa trưởng thành";
        System.out.println(result);
    }
}

